SELECT IIf([Sales Line.Document Type]=1,"SALES",IIf([Sales Line.Document Type]=5,"RETURNS","")) AS DocumentType, [Sales Line].[Customer Order Ref_], [Sales Line].Reference, [Sales Line].[Gen_ Bus_ Posting Group], [Sales Line].[VAT Bus_ Posting Group], [Sales Line].No_ AS ItemNo_, [Sales Line].Type, [Sales Line].[Model Item No_], [Sales Line].[Unit of Measure], [Sales Line].[Variable Code 01], [Sales Line_1].[Assortment Code], [Sales Line].[Delete Reason], [Sales Line].[Sales_Purchase Status Code], [Sales Line].[Sales_Purchase Status - Item], [Sales Line].[Delete Date], [Sales Line].[Customer Price Group], [Sales Line].[Average Unit Price], [Sales Header].[Order Date], [Sales Header].[Subject 1], Salesperson_Purchaser_2.Name AS Subject1Name, [Sales Header].[Subject 2], Salesperson_Purchaser_3.Name AS Subject2Name, Salesperson_Purchaser_1.Code AS CapozonaCodice, Salesperson_Purchaser_1.Name AS Capozona, [Sales Header].[Salesperson Code], Salesperson_Purchaser.Name AS Salesperson, [Sales Line].[Variable Code 01] AS ColorCode, [Sales Header].[Bill-to Customer No_], [Sales Header].[Bill-to Name], [Sales Header].[Sell-to Customer No_], [Sales Header].[Securities Received], [Sales Line].[Document No_], [Sales Line].[Line No_], IIf([Order Type]=1,"Riass.",IIf([order type]=2,"Pronto",IIf([order type]=3,"Stock",IIf([order type]=4,"Sost.",IIf([order type]=0,"Progr",IIf([order type]=5,"PreSeason",IIf([order type]=17,"Commerciale",IIf([order type]=18,"Selection","?")))))))) AS OrderType, Format(Month([Order date]),"00") & "/" & IIf(Day([order date])<11,"1",IIf(Day([order date])<21,"2","3")) AS OrderPeriod, IIf([Sales Line.document type]=1,Val([Sales Line.No_ of Pairs]),-Val([Sales Line.No_ of Pairs])) AS PairsSold, IIf([Sales Line.document type]=1,Val([Sales Line.Quantity]),-Val([Sales Line.Quantity])) AS QuantitySold, [Sales Line].[Currency Code], IIf([Sales Line.document type]=1,(Val([Sales Line.Line Amount])-Val([Sales Line.Inv_ Discount Amount])),-(Val([Sales Line.Line Amount])-Val([Sales Line.Inv_ Discount Amount]))) AS ValueSold, Val([Sales Line.Quantity Shipped]) AS QuantityShipped, IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity shipped])/Val([Sales Line.quantity])*Val([Sales Line.no_ of pairs]),0) AS PairsShipped, IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity shipped])/Val([Sales Line.quantity])*[ValueSold],0) AS ValueShipped, IIf([Sales Line.document type]=1,Val([Sales Line.Quantity Invoiced]),0) AS QuantityInvoiced, IIf([Sales Line.document type]=1,IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity invoiced])/Val([Sales Line.quantity])*Val([Sales Line.no_ of pairs]),0),0) AS PairsInvoiced, IIf([Sales Line.document type]=1,IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity invoiced])/Val([Sales Line.quantity])*[ValueSold],0)) AS ValueInvoiced, -Val([Sales Line.Return Qty_ Received]) AS QuantityReturned, IIf(Val([Sales Line.quantity])>0,-Val([Sales Line.Return Qty_ Received])/Val([Sales Line.quantity])*Val([Sales Line.no_ of pairs]),0) AS PairsReturned, IIf(Val([Sales Line.quantity])>0,Val([Sales Line.Return Qty_ Received])/Val([Sales Line.quantity])*[ValueSold],0) AS ValueReturned, IIf([Sales Line.document type]=5,-Val([Sales Line.Quantity Invoiced]),0) AS QuantityCredited, IIf([Sales Line.document type]=5,IIf(Val([Sales Line.quantity])>0,-Val([Sales Line.quantity invoiced])/Val([Sales Line.quantity])*Val([Sales Line.no_ of pairs]),0),0) AS PairsCredited, IIf([Sales Line.document type]=5,IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity invoiced])/Val([Sales Line.quantity])*[ValueSold],0),0) AS ValueCredited, Val([sales line.Subject 1 Commission _]) AS ProvvigioneSoggetto1, Val([sales line.Subject 2 Commission _]) AS ProvvigioneSoggetto2, Val([sales line.Area Manager Commission _]) AS ProvvigioneCapozona, Val([sales line.salesperson commission _]) AS ProvvigioneAgente, [Sales Line].[Return Reason Code] AS ReturnReasonCode, [Sales Header].[Ship-to Code], [Sales Header].[Ship-to Name] AS ClienteSpedizione, [Sales Header].[Ship-to Name 2] AS ClienteSpedizione2, [Sales Header].[Ship-to Address] AS IndirizzoSpedizione, [Sales Header].[Ship-to Address 2] AS IndirizzoSpedizione2, [Sales Header].[Ship-to City] AS CittaSpedizione, [Sales Header].[Ship-to Post Code] AS CodicePostaleSpedizione, [Sales Header].[Ship-to County] AS CountySpedizione, [Sales Line].[Requested Delivery Date], IIf(IsNull([qsoloVendItem-DatiBolleAperteRilasciate.order no_]),0,[PaiaInBollaTotale]) AS PairsReadyForShippingTotale, IIf(IsNull([qsoloVendItem-DatiBolleAperteRilasciate.order no_]),0,[quantitainbollatotale]) AS QuantityReadyForShippingTotale, IIf(IsNull([qsoloVendItem-DatiBolleAperteRilasciate.order no_]),0,IIf(Val([sales line.quantity])>0,Nz([quantitainbollatotale])/Val([sales line.quantity])*[ValueSold],0)) AS ValueReadyForShippingTotale, IIf(IsNull([qsoloVendItem-DatiBolleAperteRilasciate.order no_]),0,[PaiaInBollaRilasciate]) AS PairsReadyForShippingRilasciate, IIf(IsNull([qsoloVendItem-DatiBolleAperteRilasciate.order no_]),0,[quantitainbollarilasciate]) AS QuantityReadyForShippingRilasciate, IIf(IsNull([qsoloVendItem-DatiBolleAperteRilasciate.order no_]),0,IIf(Val([sales line.quantity])>0,Nz([quantitainbollarilasciate])/Val([sales line.quantity])*[ValueSold],0)) AS ValueReadyForShippingRilasciate, IIf(IsNull([qsoloVendItem-DatiBolleAperteRilasciate.order no_]),0,[PaiaInBollaAperte]) AS PairsReadyForShippingAperte, IIf(IsNull([qsoloVendItem-DatiBolleAperteRilasciate.order no_]),0,[quantitainbollaaperte]) AS QuantityReadyForShippingAperte, IIf(IsNull([qsoloVendItem-DatiBolleAperteRilasciate.order no_]),0,IIf(Val([sales line.quantity])>0,Nz([quantitainbollaaperte])/Val([sales line.quantity])*[ValueSold],0)) AS ValueReadyForShippingAperte, [Variable Code].[Variable Code] AS Taglia, [Variable Code].[Order Variable Code] AS OrdinamentoTaglia, [Sales Header].[Payment Terms Code], [Sales Header].[Payment Method Code], [Sales Header].[Invoice Discount Calculation] AS CalcoloScontoFattura, Val([Sales Header.Invoice Discount Value]) AS ScontoFattura, IIf([Consignment]=True,"SI","NO") AS ContoVendita, Val([Right on Return _]) AS PercentualeDirittoAlReso, [Sales Header].Note, [Sales Header].[Campaign No_], Val([Sales Line.Line Discount _]) AS ScontoRiga, Val([Sales Line.Discount 1 _]) AS Sconto1Riga, Val([Sales Line.Discount 2 _]) AS Sconto2Riga, Val([Sales Line.Discount 3 _]) AS Sconto3Riga, IIf([Anomalous]=1,"X"," ") AS Anomalo, IIf([Not Anomalous]=1,"X"," ") AS NonAnomalo, [Sales Header].[Anomalous Date], IIf([Checked]=1,"X"," ") AS Verificato, [Sales Header].[Checked Date], [Sales Header].[Budget No_], [Sales Header].[Course Date] AS DataDecorrenza, [Sales Header].[KIMO_FASHION SO No_] AS KimoOrder, [Sales Header].[Shipment Method Code] AS ShipmentMethodCode, [Shipment Method].Description AS ShipmentMethodDescription, [Sales Header].[Transport Reason Code], [Transport Reason Code].Description AS TransportReasonCodeDescription, [Sales Line].[Location Code], [Sales Header].[Shipping Agent Code], [Sales Header].[Shipping Agent Service Code], dateprenotazionipervendite.[Date Reservation], [Sales Header].[Fast Shipping], [Sales Line].[Model Cross Reference]
FROM (((((((((([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document No_] = [Sales Header].No_) AND ([Sales Line].[Document Type] = [Sales Header].[Document Type])) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) INNER JOIN [Variable Code] ON ([Sales Line].[Variable Group 02] = [Variable Code].[Variable Group]) AND ([Sales Line].[Variable Code 02] = [Variable Code].[Variable Code])) INNER JOIN [Sales Line] AS [Sales Line_1] ON ([Sales Line].[Document No_] = [Sales Line_1].[Document No_]) AND ([Sales Line].[Original Line No_] = [Sales Line_1].[Line No_])) LEFT JOIN [qSoloVendItem-DatiBolleAperteRilasciate] ON ([Sales Line].[Line No_] = [qSoloVendItem-DatiBolleAperteRilasciate].[Order Line No_]) AND ([Sales Line].[Document No_] = [qSoloVendItem-DatiBolleAperteRilasciate].[Order No_])) LEFT JOIN [Shipment Method] ON [Sales Header].[Shipment Method Code] = [Shipment Method].Code) LEFT JOIN Salesperson_Purchaser AS Salesperson_Purchaser_1 ON [Sales Header].[Area Manager Code] = Salesperson_Purchaser_1.Code) LEFT JOIN Salesperson_Purchaser AS Salesperson_Purchaser_2 ON [Sales Header].[Subject 1] = Salesperson_Purchaser_2.Code) LEFT JOIN Salesperson_Purchaser AS Salesperson_Purchaser_3 ON [Sales Header].[Subject 2] = Salesperson_Purchaser_3.Code) LEFT JOIN [Transport Reason Code] ON [Sales Header].[Transport Reason Code] = [Transport Reason Code].Code) LEFT JOIN dateprenotazionipervendite ON ([Sales Line].[Line No_] = dateprenotazionipervendite.[Sales Line No_]) AND ([Sales Line].[Document No_] = dateprenotazionipervendite.[Sales Document No_])
WHERE (((IIf([Sales Line.Document Type]=1,"SALES",IIf([Sales Line.Document Type]=5,"RETURNS","")))<>"") AND (([Sales Line].Type)=2) AND (([Sales Header].[Salesperson Code])=[forms]![principale]![filtroagenteanalisi]) AND (([Sales Header].[Selling Season Code])=[filtroStagione]) AND (([Sales Header].[Shortcut Dimension 2 Code])=[filtroMarchio]));

